const raw = $json.chatInput || $json.message || $json.text || $json.body?.chatInput || $json.body?.message || $json.body?.text || "";
const sessionId = $json.body?.sessionId || $json.sessionId || ('rfi-' + $execution.id);
const normalized = String(raw || "").replace(/\r\n/g, "\n").trim();

if (!normalized) {
  return [{ json: { questionNumber: 1, question: "", rawQuestion: "", sessionId, originalInput: "" } }];
}

const matches = normalized.match(/^\s*\d+\.\s*Question:.*?(?=^\s*\d+\.\s*Question:|\Z)/gms)
  || normalized.match(/^\s*\d+\.\s+.*?(?=^\s*\d+\.\s+|\Z)/gms)
  || normalized.match(/Question:.*?(?=^Question:|\Z)/gms)
  || [normalized];

return matches
  .map((block, index) => {
    const cleaned = String(block || "").trim();
    const questionMatch = cleaned.match(/Question:\s*(.+?)(?:\nAnswer:|$)/is);
    const question = (questionMatch?.[1] || cleaned).trim();

    return {
      json: {
        questionNumber: index + 1,
        question,
        rawQuestion: cleaned,
        sessionId,
        originalInput: normalized
      }
    };
  })
  .filter((item) => item.json.question);

const NOT_CONFIRMED = 'Not confirmed in the approved knowledge base.';
const items = $input.all();

const answers = items
  .map((item) => {
    const json = item.json || {};
    const forcedNotConfirmed = Boolean(json.forcedNotConfirmed);
    const modelAnswer = String(json.output || json.answer || json.message || json.text || '').trim();

    let answer = modelAnswer;
    if (forcedNotConfirmed) {
      answer = NOT_CONFIRMED;
    }

    if (!answer) {
      answer = NOT_CONFIRMED;
    }

    return {
      questionNumber: json.questionNumber || 1,
      question: json.question || json.rawQuestion || '',
      answer,
      forcedNotConfirmed,
      notConfirmedReason: json.notConfirmedReason || '',
      retrievalDiagnostics: json.retrievalDiagnostics || null,
      sessionId: json.sessionId || '',
      sources: json.sources || json.citations || []
    };
  })
  .sort((a, b) => a.questionNumber - b.questionNumber);

const successful = answers.filter((item) => String(item.answer || '').trim().length > 0).length;
const output = answers.length <= 1
  ? (answers[0]?.answer || NOT_CONFIRMED)
  : `Processed ${answers.length} questions (${successful} successful).\n\n${answers.map((item) => `${item.questionNumber}. Question: ${item.question}\nAnswer: ${item.answer}`).join("\n\n")}`;

return [{
  json: {
    output,
    answers,
    sessionId: answers[0]?.sessionId || '',
    sources: answers.flatMap((item) => item.sources || [])
  }
}];

const MIN_SCORE = 0.4;
const ENTITY_GROUPS = [
  { key: 'twdc', aliases: [/\btwdc\b/i, /\bthe walt disney company\b/i, /\bdisney\b/i] },
  { key: 'tradedoubler', aliases: [/\btradedoubler\b/i] }
];

function getOriginalQuestion() {
  try {
    return $('Split Questions').item.json;
  } catch (error) {
    try {
      return $('Split Questions').first().json;
    } catch (innerError) {
      return {};
    }
  }
}

function detectEntityGroups(text) {
  const hay = String(text || '');
  return ENTITY_GROUPS
    .filter((group) => group.aliases.some((pattern) => pattern.test(hay)))
    .map((group) => group.key);
}

function toScore(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function normalizeHit(item, index) {
  const json = item.json || {};
  const document = json.document || {};
  const metadata = json.metadata || document.metadata || {};
  const text = document.pageContent
    || json.pageContent
    || json.text
    || json.content
    || json.chunk_text
    || json.starter_answer
    || metadata.starter_answer
    || metadata.chunk_text
    || '';

  return {
    rank: index + 1,
    score: toScore(json.score ?? json.similarity ?? json.similarityScore ?? document.score),
    text: String(text || '').trim(),
    metadata,
    question_id: metadata.question_id || json.question_id || '',
    evidence_reference: metadata.evidence_reference || json.evidence_reference || '',
    source_file: metadata.source_file || metadata.source || json.source || document.source || ''
  };
}

function keepOrReject(hit, askedGroups) {
  if (hit.score !== null && hit.score < MIN_SCORE) {
    return { keep: false, reason: 'low_score' };
  }

  if (askedGroups.length > 0) {
    const searchable = [
      hit.text,
      hit.source_file,
      hit.evidence_reference,
      JSON.stringify(hit.metadata || {})
    ].join('\n');
    const hitGroups = detectEntityGroups(searchable);

    if (hitGroups.length > 0 && !hitGroups.some((group) => askedGroups.includes(group))) {
      return { keep: false, reason: 'entity_mismatch' };
    }
  }

  return { keep: true, reason: 'accepted' };
}

const original = getOriginalQuestion();
const questionText = `${original.question || ''} ${original.rawQuestion || ''}`;
const askedGroups = detectEntityGroups(questionText);

const rawHits = $input.all().map(normalizeHit).filter((hit) => hit.text || hit.evidence_reference || hit.source_file);
const curatedHits = [];
const curatedRejectedHits = [];

for (const hit of rawHits) {
  const decision = keepOrReject(hit, askedGroups);
  if (decision.keep) {
    curatedHits.push(hit);
  } else {
    curatedRejectedHits.push({ ...hit, rejectionReason: decision.reason });
  }
}

const rejectedByScore = curatedRejectedHits.filter((hit) => hit.rejectionReason === 'low_score').length;
const rejectedByEntity = curatedRejectedHits.filter((hit) => hit.rejectionReason === 'entity_mismatch').length;

return [{
  json: {
    questionNumber: original.questionNumber || 1,
    question: original.question || original.rawQuestion || '',
    rawQuestion: original.rawQuestion || original.question || '',
    sessionId: original.sessionId || '',
    curatedHits,
    curatedRejectedHits,
    curatedDiagnostics: {
      minScore: MIN_SCORE,
      askedEntityGroups: askedGroups,
      totalHits: rawHits.length,
      keptHits: curatedHits.length,
      rejectedHits: curatedRejectedHits.length,
      rejectedByScore,
      rejectedByEntity
    }
  }
}];

