const NOT_CONFIRMED = 'Not confirmed in the approved knowledge base.';

function formatHits(label, hits) {
  if (!Array.isArray(hits) || hits.length === 0) {
    return `${label}: none`;
  }

  return `${label}:\n` + hits.slice(0, 8).map((hit, index) => {
    const meta = hit.metadata || {};
    const id = hit.question_id || meta.question_id || 'N/A';
    const source = hit.source_file || meta.source_file || meta.source || 'Unknown source';
    const ref = hit.evidence_reference || meta.evidence_reference || 'No evidence reference';
    const score = hit.score === null || hit.score === undefined ? 'n/a' : String(hit.score);
    const text = String(hit.text || '').replace(/\s+/g, ' ').trim();
    return [
      `${index + 1}. [${id}] ${source} | ${ref} | score=${score}`,
      text ? `   ${text}` : '   (no text returned)'
    ].join('\n');
  }).join('\n');
}

function hasUsefulNumber(text) {
  const matches = [...String(text || '').matchAll(/\b\d[\d,]*(?:\.\d+)?\b/g)];
  return matches.some((match) => {
    const raw = String(match[0] || '').replace(/,/g, '');
    if (!raw) return false;
    if (/^\d{4}$/.test(raw)) {
      const year = Number(raw);
      if (year >= 1900 && year <= 2100) {
        return false;
      }
    }
    return Number(raw) > 0;
  });
}

function hasQuantitativeSignal(text) {
  return /(record|records|count|volume|number|total|rows?|stored|processed|transmitted|million|thousand|dataset|entries|per day|per month|per year)/i.test(String(text || ''));
}

const question = String($json.question || $json.rawQuestion || '').trim();
const questionLower = question.toLowerCase();
const curatedHits = Array.isArray($json.curatedHits) ? $json.curatedHits : [];
const fallbackHits = Array.isArray($json.fallbackHits) ? $json.fallbackHits : [];
const allHits = [...curatedHits, ...fallbackHits];

const isQuantitativeQuestion = /(how many|number of|count\b|volume\b|#\s*of|total\b|records?\b|rows?\b|amount\b)/i.test(questionLower);
const hasQuantitativeEvidence = allHits.some((hit) => {
  const meta = hit.metadata || {};
  const combinedText = [
    hit.text,
    meta.chunk_text,
    meta.starter_answer,
    meta.canonical_question
  ].filter(Boolean).join('\n');
  return hasUsefulNumber(combinedText) && hasQuantitativeSignal(combinedText);
});

const scoredHits = allHits
  .map((hit) => Number(hit.score))
  .filter((score) => Number.isFinite(score));
const maxScore = scoredHits.length > 0 ? Math.max(...scoredHits) : null;

let forcedNotConfirmed = false;
const notConfirmedReasons = [];

if (allHits.length === 0) {
  forcedNotConfirmed = true;
  notConfirmedReasons.push('no evidence passed retrieval quality filters');
}

if (isQuantitativeQuestion && !hasQuantitativeEvidence) {
  forcedNotConfirmed = true;
  notConfirmedReasons.push('quantitative question without explicit numeric volume evidence');
}

if (maxScore !== null && maxScore < 0.4) {
  forcedNotConfirmed = true;
  notConfirmedReasons.push(`top relevance score below threshold (maxScore=${maxScore})`);
}

const retrievalDiagnostics = {
  curated: $json.curatedDiagnostics || null,
  fallback: $json.fallbackDiagnostics || null,
  allHitsCount: allHits.length,
  scoredHitsCount: scoredHits.length,
  maxScore,
  isQuantitativeQuestion,
  hasQuantitativeEvidence,
  forcedNotConfirmed,
  notConfirmedReasons
};

let preparedPrompt;
if (forcedNotConfirmed) {
  preparedPrompt = [
    `Question:\n${question}`,
    formatHits('Curated evidence', curatedHits),
    formatHits('Fallback evidence', fallbackHits),
    'Hard Rule:',
    `- Quality gate triggered: ${notConfirmedReasons.join('; ')}`,
    `- Return exactly: ${NOT_CONFIRMED}`,
    '- Do not output Evidence or any additional explanation.'
  ].join('\n\n');
} else {
  preparedPrompt = [
    `Question:\n${question}`,
    formatHits('Curated evidence', curatedHits),
    formatHits('Fallback evidence', fallbackHits),
    'Instructions:',
    '- Answer only the question shown above.',
    '- Use ONLY facts from the evidence blocks.',
    '- Prefer curated evidence over fallback evidence.',
    '- Use fallback evidence when curated evidence is missing, partial, or not directly relevant.',
    `- If the evidence does not support a direct answer, return exactly: ${NOT_CONFIRMED}`,
    '- Prefer not-confirmed over inference when the evidence is partial, indirect, or only loosely related.',
    '- Reject evidence that explicitly references a different entity than the one named in the question.',
    '- For quantitative questions, answer only if evidence explicitly contains numeric counts or volume ranges tied to the asked metric.',
    '- Do not use security-control answers (encryption/pseudonymization) to answer quantitative volume questions.',
    '- For yes/no questions, use Yes. or No. only with explicit evidence.',
    '- When confirmed, include an Evidence section with 1-3 bullets using this format: - [ID] <source file> - <evidence reference>.',
    '- If only fallback evidence supports the answer, add one line before Evidence: Legacy/expanded evidence used; verify if policy has changed.',
    '- If the answer is not confirmed, do not output Evidence or any extra explanation.'
  ].join('\n\n');
}

